import { Injectable } from '@angular/core';
import { BaseService } from '../Base/base.service';

export interface IngredientGroup {
  id: string;
  name: string;
  description?: string;
  color: string;
  sort_order: number;
  is_active: boolean;
  is_system: boolean;
  created_at: string;
  ingredient_count?: number;
}

@Injectable({
  providedIn: 'root'
})
export class IngredientGroupService extends BaseService<IngredientGroup> {

  constructor() {
    super();
    // Carica immediatamente i gruppi (sono globali)
    this.loadData();
  }

  override getTableName(): string {
    return 'ingredient_groups';
  }

  // ✅ OVERRIDE COMPLETO PER EVITARE IL FILTRO RESTAURANT_ID
  override async loadData(): Promise<void> {
    try {
      this.loadingSubject.next(true);
      
      console.log('🔄 Caricamento gruppi ingredienti (globali)...');
      
      // ⚠️ IMPORTANTE: NON USARE getCurrentRestaurantId() perché i gruppi sono globali
      // Carica TUTTI i gruppi (globali, senza filtro per ristorante)
      const { data: groups, error } = await this.supabaseService.getSupabaseClient()
        .from(this.getTableName())
        .select(`
          *,
          ingredients:ingredients(count)
        `)
        .eq('is_active', true)
        .order('sort_order')
        .order('name');

      if (error) {
        console.error('❌ Errore query gruppi:', error);
        throw error;
      }

      console.log(`✅ ${groups?.length || 0} gruppi caricati con successo`);
      
      // Processa i dati per includere il conteggio
      const processedGroups = (groups || []).map(group => ({
        ...group,
        ingredient_count: (group as any).ingredients?.[0]?.count || 0
      }));

      this.dataSubject.next(processedGroups as IngredientGroup[]);
      
    } catch (error) {
      console.error('Error loading ingredient groups:', error);
      this.handleError('loadData', error);
    } finally {
      this.loadingSubject.next(false);
    }
  }

  // ⚠️ IMPORTANTE: Override del metodo getCurrentRestaurantId per ritornare null
  override async getCurrentRestaurantId(): Promise<string | null> {
    // Per i gruppi globali, non abbiamo bisogno del restaurant_id
    return null;
  }

  getGroups(): IngredientGroup[] {
    return this.dataSubject.value;
  }

  getGroupById(id: string): IngredientGroup | undefined {
    return this.dataSubject.value.find(g => g.id === id);
  }
}