import { Injectable } from '@angular/core';
import { filter, take } from 'rxjs';
import { BaseService } from '../Base/base.service';
import { IngredientGroup } from './ingredient-group.service';

export interface IngredientType {
  id: string;
  restaurant_id: string;
  group_id?: string;
  name: string;
  description?: string;
  is_active: boolean;
  is_system: boolean;
  created_by_user_id?: string;
  created_at: string;
  group?: IngredientGroup;
  ingredient_count?: number;
}

@Injectable({
  providedIn: 'root'
})
export class IngredientTypeService extends BaseService<IngredientType> {

  constructor() {
    super();
    // Carica immediatamente le tipologie
    this.loadData();
  }

  override getTableName(): string {
    return 'ingredient_types';
  }

  override async loadData(): Promise<void> {
    try {
      this.loadingSubject.next(true);
      
      // Query semplificata senza created_by_user (che causa errori)
      const { data: types, error } = await this.supabaseService.getSupabaseClient()
        .from(this.getTableName())
        .select(`
          *,
          group:ingredient_groups(*),
          ingredients:ingredients(count)
        `)
        .eq('is_active', true)
        .order('name');

      if (error) throw error;

      // Processa i dati
      const processedTypes = (types || []).map(type => ({
        ...type,
        ingredient_count: (type as any).ingredients?.[0]?.count || 0
      }));

      this.dataSubject.next(processedTypes as IngredientType[]);
      
    } catch (error) {
      console.error('Error loading ingredient types:', error);
      this.handleError('loadData', error);
    } finally {
      this.loadingSubject.next(false);
    }
  }

async createType(type: Omit<IngredientType, 'id' | 'created_at' | 'is_system' | 'created_by_user_id'>): Promise<IngredientType | null> {
  try {
    const currentUser = await this.authService.currentUser$.pipe(take(1)).toPromise();
    const currentUserId = currentUser?.id;

    if (!currentUserId) {
      throw new Error('Utente non autenticato');
    }

    const typeToInsert = {
      ...type,
      is_system: false,
      created_by_user_id: currentUserId,
      restaurant_id: null // ✅ Usa null invece di stringa vuota
      // OPPURE rimuovi completamente questa riga se non è necessario
    };

    const { data, error } = await this.supabaseService.getSupabaseClient()
      .from(this.getTableName())
      .insert(typeToInsert)
      .select(`
        *,
        group:ingredient_groups(*)
      `)
      .single();

    if (error) throw error;

    await this.loadData();
    return data;
  } catch (error) {
    console.error('Error creating type:', error);
    return null;
  }
}

  async updateType(id: string, updates: Partial<IngredientType>): Promise<boolean> {
    try {
      const { error } = await this.supabaseService.getSupabaseClient()
        .from(this.getTableName())
        .update(updates)
        .eq('id', id);

      if (error) throw error;
      
      await this.loadData();
      return true;
    } catch (error) {
      console.error('Error updating type:', error);
      return false;
    }
  }

  async deleteType(id: string): Promise<boolean> {
    try {
      // Controlla se ci sono ingredienti associati
      const { data: ingredients, error: checkError } = await this.supabaseService.getSupabaseClient()
        .from('ingredients')
        .select('id')
        .eq('type_id', id)
        .eq('is_active', true)
        .limit(1);

      if (checkError) throw checkError;
      
      if (ingredients && ingredients.length > 0) {
        throw new Error('Non puoi eliminare una tipologia con ingredienti associati');
      }

      const { error } = await this.supabaseService.getSupabaseClient()
        .from(this.getTableName())
        .update({ is_active: false })
        .eq('id', id);

      if (error) throw error;
      
      await this.loadData();
      return true;
    } catch (error) {
      console.error('Error deleting type:', error);
      throw error;
    }
  }

  getTypes(): IngredientType[] {
    return this.dataSubject.value;
  }

  getTypeById(id: string): IngredientType | undefined {
    return this.dataSubject.value.find(t => t.id === id);
  }

  getTypesByGroup(groupId: string): IngredientType[] {
    return this.dataSubject.value.filter(t => t.group_id === groupId);
  }
}